CREATE TABLE bank_accounts (
  account_id INT PRIMARY KEY,
  owner      VARCHAR(50),
  balance    DECIMAL(10,2) CHECK (balance >= 0)
);

INSERT INTO bank_accounts VALUES
  (1, 'Alice', 1000.00),
  (2, 'Bob',   500.00),
  (3, 'Carol', 750.00);

SELECT * FROM bank_accounts;

-- Successful transaction: transfer $200 from Alice to Bob
BEGIN;
  UPDATE bank_accounts SET balance = balance - 200 WHERE account_id = 1;
  UPDATE bank_accounts SET balance = balance + 200 WHERE account_id = 2;
COMMIT;

SELECT account_id, owner, balance FROM bank_accounts ORDER BY account_id;

-- Failed transaction: Bob tries to send $1000 (he only has 700 now)
-- CHECK constraint prevents balance going negative
BEGIN;
  UPDATE bank_accounts SET balance = balance - 1000 WHERE account_id = 2;
  UPDATE bank_accounts SET balance = balance + 1000 WHERE account_id = 3;
ROLLBACK;  -- manually rollback when we catch an error

-- State should be unchanged after rollback
SELECT account_id, owner, balance FROM bank_accounts ORDER BY account_id;

CREATE TABLE inventory (
  product_id  INT PRIMARY KEY,
  name        VARCHAR(80),
  stock       INT CHECK (stock >= 0)
);

CREATE TABLE order_queue (
  order_id    SERIAL PRIMARY KEY,
  product_id  INT,
  customer    VARCHAR(50),
  qty         INT,
  status      VARCHAR(20) DEFAULT 'pending',
  FOREIGN KEY (product_id) REFERENCES inventory(product_id)
);

CREATE TABLE payment_log (
  log_id     SERIAL PRIMARY KEY,
  order_id   INT,
  amount     DECIMAL(8,2),
  paid_at    TIMESTAMP DEFAULT NOW()
);

INSERT INTO inventory VALUES (1,'Laptop',10),(2,'Mouse',100),(3,'Keyboard',50);

-- Fulfill an order: deduct stock, record order, log payment — all or nothing
BEGIN;
  -- Step 1: check and deduct inventory
  UPDATE inventory SET stock = stock - 2 WHERE product_id = 1;
  -- Step 2: create order record
  INSERT INTO order_queue (product_id, customer, qty, status)
  VALUES (1, 'Alice', 2, 'fulfilled');
  -- Step 3: log payment
  INSERT INTO payment_log (order_id, amount) VALUES (1, 1999.98);
COMMIT;

-- Verify all three tables updated
SELECT * FROM inventory WHERE product_id = 1;
SELECT * FROM order_queue;
SELECT * FROM payment_log;

CREATE TABLE employees (
  emp_id  INT PRIMARY KEY,
  name    VARCHAR(60),
  salary  DECIMAL(10,2)
);

CREATE TABLE salary_audit (
  audit_id    SERIAL PRIMARY KEY,
  emp_id      INT,
  old_salary  DECIMAL(10,2),
  new_salary  DECIMAL(10,2),
  changed_at  TIMESTAMP DEFAULT NOW(),
  changed_by  VARCHAR(50)
);

INSERT INTO employees VALUES (1,'Alice',85000),(2,'Bob',72000),(3,'Carol',65000);

-- Transaction: give Alice a raise + record in audit log
BEGIN;
  -- Capture old salary first
  -- Update salary
  UPDATE employees SET salary = 95000 WHERE emp_id = 1;
  -- Write audit record with old and new values
  INSERT INTO salary_audit (emp_id, old_salary, new_salary, changed_by)
  VALUES (1, 85000, 95000, 'admin_user');
COMMIT;

-- Verify both tables
SELECT * FROM employees ORDER BY emp_id;
SELECT * FROM salary_audit;
